-- 只能创建2天以内的协访
UPDATE `object_validations` SET `label` = '只能创建2天以内的协访', `description` = '只能创建2天以内的协访', `trigger_code` = 'from django.utils.timezone import utc, localtime\nfrom django.utils import timezone\nimport datetime\nif instance:\n    if instance.coaching_date:\n        edit_time = instance.coaching_date\n        now = datetime.datetime.now()\n        allow_start_date = (now - datetime.timedelta(days=2, hours=0, minutes=0, seconds=0)).date()\n        if type(instance.coaching_date) == datetime.date:\n            edit_time = instance.coaching_date\n        else:\n            edit_time = datetime.datetime.strptime(instance.coaching_date, \'%Y-%m-%d\').date()\n        if edit_time < allow_start_date:\n            message = \'仅可创建2天以内的协访\'\n            raise create_validation_trigger_rule_errors(message)' WHERE (`id` = 'hxf43f70-e980-11e9-b9aa-0298a739d4ab');
