 \"values\": {\n                        \"am\": [\n                            \"am\"\n                        ],\n                        \"pm\": [\n                            \"pm\"\n                        ]\n                    }\n                }\n            },\n            \"event\": {\n                \"__default__\": {\n                    \"column_names\": [\n                        \"event_start_time\",\n                        \"event_end_time\"\n                    ],\n                    \"type\": \"range\"\n                },\n                \"cs_department\": {\n                    \"column_names\": [\n                        \"date_1\",\n                        \"picklist_2\"\n                    ],\n                    \"type\": \"ampm\",\n                    \"values\": {\n                        \"am\": [\n                            \"am\"\n                        ],\n                        \"pm\": [\n                            \"pm\"\n                        ]\n                    }\n                },\n               \"cs_patient_education_meeting\": {\n                    \"column_names\": [\n                        \"date_1\",\n                        \"picklist_2\"\n                    ],\n                    \"type\": \"ampm\",\n                    \"values\": {\n                        \"am\": [\n                            \"am\"\n                        ],\n                        \"pm\": [\n                            \"pm\"\n                        ]\n                    }\n                }\n            },\n            \"weekly_plan\": {\n                \"__default__\": {\n                    \"values\": {\n                        \"am\": [\n                            \"am\"\n                        ],\n                        \"pm\": [\n                            \"pm\"\n                        ]\n                    },\n                    \"column_names\": [\n                        \"date\",\n                        \"ampm\"\n                    ],\n                    \"type\": \"ampm\"\n                },\n                \"weekly_plan_coaching_plans\": {\n                    \"type\": \"ampm\",\n                    \"column_names\": [\n                        \"date\",\n                        \"ampm\"\n                    ],\n                    \"values\": {\n                        \"am\": [\n                            \"am\"\n                        ],\n                        \"pm\": [\n                            \"pm\"\n                        ]\n                    }\n                },\n                \"time_off_territory\": {\n                    \"type\": \"full\",\n                    \"column_names\": [\n                        \"date\",\n                        \"ampm\"\n                    ],\n                    \"values\": {\n                        \"am\": [\n                            \"am\"\n                        ],\n                        \"pm\": [\n                            \"pm\"\n                        ]\n                    }\n                }\n            }\n        }\n    }\n} ' WHERE (`id` = '95');
